  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id_rph`),
  UNIQUE KEY `rph_kode_rph_unique` (`kode_rph`),
  KEY `rph_id_bkph_foreign` (`id_bkph`),
