--
-- Table structure for table `user`
--

DROP TABLE IF EXISTS `user`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `user` (
  `id_user` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `nama` varchar(100) NOT NULL,
  `username` varchar(50) NOT NULL,
  `password` varchar(255) NOT NULL,
  `role` enum('KPH','KRPH') NOT NULL,
  `id_rph` int(10) unsigned DEFAULT NULL COMMENT 'Wajib diisi jika role = KRPH. NULL utk role KPH (akses seluruh KPH Kediri)',
  `status_aktif` tinyint(1) NOT NULL DEFAULT 1,
  `remember_token` varchar(100) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id_user`),
  UNIQUE KEY `user_username_unique` (`username`),
  KEY `user_id_rph_foreign` (`id_rph`),
  CONSTRAINT `user_id_rph_foreign` FOREIGN KEY (`id_rph`) REFERENCES `rph` (`id_rph`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `chk_user_role_wilayah` CHECK (`role` = 'KRPH' and `id_rph` is not null or `role` = 'KPH')
) ENGINE=InnoDB AUTO_INCREMENT=109 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

